q.srcdoc='          <!DOCTYPE html>\n          <html>\n          <head>\n              <title>Examples. Setting a custom placemark image</title>\n              <meta http-equiv="Content-Type" content="text/html; charset=UTF-8" />\n              <script src="https://api-maps.yandex.ru/2.1/?lang=ru_RU&amp;apikey='+this.a.a.x+"\" type=\"text/javascript\"></script>\n              <style>\n                  html, body, #map {\n                      width: 100%; height: 100%; padding: 0; margin: 0;\n                  }\n              </style>\n              <script>\n              var myPlacemarks = [];\n              var myMap;\n              ymaps.ready(init);\n              function init() {\n                myMap = new ymaps.Map('map', {\n                  center: [55.76, 37.64], // Moscow\n                  zoom: 10,\n                  controls: [],\n                }, {\n                  searchControlProvider: 'yandex#search',\n                  suppressMapOpenBlock: true,\n                });\n                \n                setTimeout(function() {\n                  /// place elements of maps again after changing layout of map\n                  changeMapTheme("+this.b+");\n                  myPlacemarks.forEach(function (e) {\n                    myMap.geoObjects.add(e);\n                  });\n                }, 500);\n              \n                // ---------CAMERA MOVE BEGIN---------\n              \n                // On action begin\n                myMap.events.add('actionbegin', onActionBegin);\n              \n                //a callback function to do something with the new boundaries\n                function onActionBegin(e) {\n                  window.parent.postMessage({ event: \"onCameraMoveBegin\" }, \"*\");\n                }\n              \n                // ---------CAMERA MOVE END---------\n              \n                // On action begin\n                myMap.events.add('actionend', onActionEnd);\n              \n                //a callback function to do something with the new boundaries\n                function onActionEnd(e) {\n                  window.parent.postMessage({ event: \"onCameraMoveEnd\" }, \"*\");\n                }\n              \n                // -----------------------------------\n              \n                // \u0421\u043b\u0443\u0448\u0430\u0435\u043c \u043a\u043b\u0438\u043a \u043d\u0430 \u043a\u0430\u0440\u0442\u0435.\n                myMap.events.add('click', function (e) {\n                  var coords = e.get('coords');\n                  window.parent.postMessage({ event: \"onMapTap\", lat: coords[0], lon: coords[1] }, \"*\");\n                });\n              }\n              \n              window.parent.addEventListener('message', handleMessage, false);\n              \n              function handleMessage(message) {\n                var parsed = message.data;\n                if (parsed.functionToCall == 'addMarkersOnMap') {\n                  addMarkersOnMap(JSON.parse(parsed.data));\n                } else if (parsed.functionToCall == 'focusToPoint') {\n                  var data = JSON.parse(parsed.data);\n                  focusToPoint(data.center, data.zoom);\n                } else if (parsed.functionToCall == 'focusToBox') {\n                  focusToBox(JSON.parse(parsed.data));\n                } else if (parsed.functionToCall == 'changeMapTheme') {\n                  changeMapTheme(parsed.data);\n                }\n              }\n              \n              /*\n              map markers is list of objects with structure of MapObjectEntityBase\n              */\n              function addMarkersOnMap(mapMarkers) {\n                myPlacemarks.forEach(function (e) {\n                  myMap.geoObjects.remove(e);\n                });\n                myPlacemarks = [];\n                mapMarkers.forEach(function (e) {\n                  if (e.type == 'placemark') {\n                    var newPlacemark = createPlacemark(e);\n                    myMap.geoObjects.add(newPlacemark);\n                    myPlacemarks.push(newPlacemark);\n                  } else if (e.type == 'polyline') {\n                    var newLine = createLine(e);\n                    myMap.geoObjects.add(newLine);\n                    myPlacemarks.push(newLine);\n                  }\n                });\n              }\n              \n              function focusToPoint(center, zoom) {\n                myMap.setCenter(center, zoom);\n              }\n              \n              function focusToBox(cords) {\n                myMap.setBounds([cords.northEast, cords.southWest], {});\n              }\n              \n              function changeMapTheme(isDark) {\n                var mapType = isDark ? 'dark' : 'light';\n                const MAP = 'custom#' + mapType;\n                ymaps.layer.storage.add(MAP, function mapLayer() {\n                    return new ymaps.Layer('https://core-renderer-tiles.maps.yandex.net/tiles?l=map' + ((mapType == 'dark') ? ('&theme=dark') : ('')) + '&%c&%l');\n                });\n                ymaps.mapType.storage.add(MAP, new ymaps.MapType(mapType, [MAP]));\n                myMap.setType(MAP);\n              }\n              \n              function createPlacemark(mapMarker) {\n                return new ymaps.Placemark(mapMarker.coordinate, {}, {\n                  preset: 'islands#dotIcon',\n                  iconColor: '#' + mapMarker.color,\n                  iconLayout: 'default#image',\n                  iconImageSize: mapMarker.pin.iconImageSize,\n                  iconImageOffset: mapMarker.pin.iconImageOffset,\n                  iconImageHref: mapMarker.pin.path + '_' + mapMarker.color + '.svg',\n                  draggable: false,\n                });\n              }\n              \n              function createLine(line) {\n                return new ymaps.Polyline(line.path, {}, {\n                  hasBalloon: false,\n                  draggable: false,\n                  strokeColor: '#' + line.color,\n                  strokeWidth: line.strokeWidth,\n                  hasHint: false,\n                });\n              }\n              </script>\n          </head>\n          <body>\n          <div id=\"map\"></div>\n          </body>\n          </html>\n        "
